+
+    #[test]
+    fn pane_priority_all_five_distinct() {
+        let priorities = [
+            PanePriority::Background,
+            PanePriority::Low,
+            PanePriority::Medium,
+            PanePriority::High,
+            PanePriority::Critical,
+        ];
+        for (i, a) in priorities.iter().enumerate() {
+            for (j, b) in priorities.iter().enumerate() {
+                if i == j {
+                    assert_eq!(a, b);
+                } else {
+                    assert_ne!(a, b);
+                }
+            }
+        }
+    }
